using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly string[] _classLabels;
    private readonly EvaluationResponse _evaluationMetrics;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 0);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Combine text features and build pipeline
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract class labels from the trained model's key-value mapping
        var transformedData = _model.Transform(dataView);
        var labelColumn = transformedData.Schema["PredictedLabel"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        // Read labels from the Score column's slot names (one per class)
        var scoreColumn = transformedData.Schema["Score"];
        scoreColumn.GetSlotNames(ref slotNames);
        _classLabels = slotNames.DenseValues()
            .Select(v => v.ToString()).ToArray();

        // Evaluate using cross-validation for more meaningful metrics on small datasets
        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");
        var bestFold = cvResults
            .OrderByDescending(r => r.Metrics.MicroAccuracy).First();
        var metrics = bestFold.Metrics;

        // Also evaluate on training data for per-class metrics
        var predictions = _model.Transform(dataView);
        var fullMetrics = _mlContext.MulticlassClassification
            .Evaluate(predictions, labelColumnName: "Label");

        var perClass = new List<PerClassMetrics>();
        for (int i = 0; i < fullMetrics.PerClassPrecision.Count; i++)
        {
            perClass.Add(new PerClassMetrics
            {
                Class = i < _classLabels.Length ? _classLabels[i] : $"Class{i}",
                Precision = fullMetrics.PerClassPrecision[i],
                Recall = fullMetrics.PerClassRecall[i],
                F1Score = 2 * (fullMetrics.PerClassPrecision[i] * fullMetrics.PerClassRecall[i])
                    / (fullMetrics.PerClassPrecision[i] + fullMetrics.PerClassRecall[i])
            });
        }

        _evaluationMetrics = new EvaluationResponse
        {
            MicroAccuracy = (float)metrics.MicroAccuracy,
            MacroAccuracy = (float)metrics.MacroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction,
            PerClassMetrics = perClass.ToArray()
        };
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < _classLabels.Length; i++)
        {
            confidence[_classLabels[i]] = prediction.Score[i];
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    public EvaluationResponse GetEvaluationMetrics() => _evaluationMetrics;
}

